148→function validateColorName(value: unknown): value is HudColorName {
149→  return value === 'red'
150→    || value === 'green'
151→    || value === 'yellow'
152→    || value === 'magenta'
153→    || value === 'cyan'
154→    || value === 'brightBlue'
155→    || value === 'brightMagenta';
156→}
157→
158→const HEX_COLOR_PATTERN = /^#[0-9a-fA-F]{6}$/;
159→
160→function validateColorValue(value: unknown): value is HudColorValue {
161→  if (validateColorName(value)) return true;
162→  if (typeof value === 'number' && Number.isInteger(value) && value >= 0 && value <= 255) return true;
163→  if (typeof value === 'string' && HEX_COLOR_PATTERN.test(value)) return true;
164→  return false;
165→}
166→
167→function validateElementOrder(value: unknown): HudElement[] {
168→  if (!Array.isArray(value) || value.length === 0) {
169→    return [...DEFAULT_ELEMENT_ORDER];
170→  }
171→
172→  const seen = new Set<HudElement>();
173→  const elementOrder: HudElement[] = [];
174→
175→  for (const item of value) {
176→    if (typeof item !== 'string' || !KNOWN_ELEMENTS.has(item as HudElement)) {
177→      continue;
178→    }
179→
180→    const element = item as HudElement;
181→    if (seen.has(element)) {
182→      continue;
183→    }
184→
185→    seen.add(element);
186→    elementOrder.push(element);
187→  }
188→
189→  return elementOrder.length > 0 ? elementOrder : [...DEFAULT_ELEMENT_ORDER];
190→}
